  func Icon(name string, extraClasses ...string) template.HTML {
        iconName := name
        var embeddedClasses string
        if i := strings.IndexByte(name, ' '); i > 0 {
                iconName = name[:i]
                embeddedClasses = name[i+1:]
        }
        def, ok := registry[iconName]
        if !ok {
                return template.HTML(fmt.Sprintf(`<!-- icon not found: %s -->`, template.HTMLEscapeString(iconName)))
        }

        cls := "icon icon-" + iconName
        if embeddedClasses != "" {
                cls += " " + embeddedClasses
        }
        if len(extraClasses) > 0 {
                cls += " " + strings.Join(extraClasses, " ")
        }

        return template.HTML(fmt.Sprintf(
                `<svg class="%s" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 %d %d" fill="currentColor" aria-hidden="true"><path d="%s"/></svg>`,
                cls, def.W, def.H, def.D,
        ))
  }

  func IconExists(name string) bool {
        _, ok := registry[name]
        return ok
  }

  func AllIconNames() []string {
        names := make([]string, 0, len(registry))
        for k := range registry {
                names = append(names, k)
        }
        return names
  }

  func IconSVGJSON() map[string]string {
        result := make(map[string]string, len(registry))
        for name, def := range registry {
                result[name] = fmt.Sprintf(
                        `<svg class="icon icon-%s" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 %d %d" fill="currentColor" aria-hidden="true"><path d="%s"/></svg>`,
                        name, def.W, def.H, def.D,
                )
        }
        return result
  }
  